```javascript
function solution(values, targetSum) {
  let minCoinsNeeded = Number.MAX_VALUE;

  const getMinCoinsForValueHelper = (valueToFind, currentAmountOfChange) => {
    if (currentAmountOfChange === targetSum) {
      return 0;
    }

    if (minCoinsNeeded > currentAmountOfChange) {
      minCoinsNeeded = currentAmountOfChange;
    }

    for (let index = 0; index < values.length; index++) {
      const coinValue = values[index];
      if (coinValue <= valueToFind) {
        getMinCoinsForValueHelper(
          valueToFind - coinValue,
          currentAmountOfChange + 1
        );
      }
    }
  };

  getMinCoinsForValueHelper(targetSum, 0);

  return minCoinsNeeded;
}
