    ```java
    import java.util.Arrays;
    import java.util.stream.IntStream;

    public class HasOneDifference{
        private final char[] charsA;
        private final char[] charsB;

        public HasOneDifference(final String a, final String b){
            charsA = a.toCharArray();
            charsB = b.toCharArray();

            Arrays.sort(charsA);
            Arrays.sort(charsB);
        }

        public boolean compare(){
            IntStream stream = IntStream.range(0, charsA.length).filter((index)->charsA[index]!=charsB[index]).limit(2);
            long differenceCount = stream.count()==2?false:(long)(Math.abs(stream.findFirst().getAsLong())+1);
            return differenceCount==1;
        }
    }
    ```

