public static int solution(int N) {
	// Write your code here
	int count3 = 0, count7 = 0, count3and7 = 0;
	for (int i = 1; i <= N; ++i) {
		if ((i % 3 == 0)) {
			count3++;
		}
		if ((i % 7 == 0)) {
			count7++;
		}
		if ((i % 3 == 0) && (i % 7 == 0)) {
			count3and7++;
		}
	}
	return count3 + count7 - count3and7;
}
```
